package cmd

import (
	"fmt"
	"strings"

	"github.com/sandcastle/cli/api"
	"github.com/sandcastle/cli/internal/config"
	"github.com/spf13/cobra"
)

func init() {
	rootCmd.AddCommand(execCmd)
}

var execCmd = &cobra.Command{
	Use:     "exec <name> -- <command...>",
	Aliases: []string{"x"},
	Short:   "Run a single command in a sandbox",
	Args:  cobra.MinimumNArgs(2),
	RunE: func(cmd *cobra.Command, args []string) error {
		name := args[0]
		remoteCmd := strings.Join(args[1:], " ")

		client, err := api.NewClient()
		if err != nil {
			return err
		}
		printServer(client)

		sandbox, err := findSandboxByName(client, name)
		if err != nil {
			return fmt.Errorf("sandbox %q not found", name)
		}

		info, err := client.ConnectInfo(sandbox.ID)
		if err != nil {
			return err
		}

		cfg, err := config.Load()
		if err != nil {
			return err
		}
		prefs := cfg.LoadPreferences()

		return sshExec(info.Host, info.Port, info.User, remoteCmd, prefs.SSHExtraArgs)
	},
}

